VALUES
  ('optician-moex-02619', 'optician', 'optician-moex-106-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一般眼鏡配置時，下列敘述何者錯誤？', '["兩鏡框幾何中心距離應小於瞳孔距離", "鏡框的弧度要儘量配合鏡片的弧度", "高度數鏡片的光學中心垂直位移影響較低度數明顯", "雙光鏡片的鏡片高度要依個人習慣與需求調整"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "13bf039f1ee9", "answer_pdf_sha1": "37c3ea05d044", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02620', 'optician', 'optician-moex-106-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '醫師處方箋上註明OD:-1.50DS/-1.00DC×180，OS:-2.00DS/-1.50DC×180，下列敘述何者正確？①左眼球', '["左眼球面度數-2.00 D", "左眼等效球鏡度（spherical equivalent）是-2.75 D", "左眼等 效球鏡度是-3.5 D", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "13bf039f1ee9", "answer_pdf_sha1": "37c3ea05d044", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 47, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02621', 'optician', 'optician-moex-106-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一個病人有右眼外隱斜視，他的近視度數是-6.00 D，此病人需要右眼4Δ基底朝內的稜鏡處方才能緩解眼 睛疲勞症狀，病人原先瞳孔間距是 60 mm，若完全使用偏心的方法將稜鏡的處方加入透鏡中，則兩鏡片 光學中心距離應該為多少？', '["72.6 mm", "66.6 mm", "58.6 mm", "60.2 mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "13bf039f1ee9", "answer_pdf_sha1": "37c3ea05d044", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02622', 'optician', 'optician-moex-106-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '一個病人原先是戴著+9.00 D球面透鏡（頂點距離是12 mm），他因為接受鼻手術需要新的眼鏡，新眼鏡 的頂點距離必須調整到22 mm病人才能接受，則新眼鏡的度數要調整到多少？', '["+7.25 D", "+8.25 D", "+9.25 D", "+10.25 D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "13bf039f1ee9", "answer_pdf_sha1": "37c3ea05d044", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02623', 'optician', 'optician-moex-106-d6d7f3e6', 'sub-optician-02', NULL, 'single_choice', '我們可以用眼鏡調整外觀，對於一個右眼無視力且因眼球萎縮而放義眼的病人，下列那一個做法可以用 來改善外觀上兩眼的不對稱性？', '["在右眼前放正球面透鏡", "在右眼前放負球面透鏡", "右眼有可能會因眼球萎縮而眼瞼下垂，可以放軸位在90度的正圓柱透鏡", "右眼可能因為橫向眼瞼裂較窄，可以放軸位在180度的正圓柱透鏡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "13bf039f1ee9", "answer_pdf_sha1": "37c3ea05d044", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "113", "s": "1109", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼鏡光學概要", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02624', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於游泳時配戴隱形眼鏡的敘述，下列何者錯誤？', '["配戴隱形眼鏡游泳會增加角膜感染的風險", "含氯的游泳池水會因為隱形眼鏡吸附而造成眼部的不適", "配戴隱形眼鏡游泳，建議使用硬式隱形眼鏡", "配戴隱形眼鏡游泳，建議使用日拋型隱形眼鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02625', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡清潔液引起之敏感發炎反應（hypersensitivity reaction）敘述，下列何者錯誤？', '["可在接觸後幾分鐘、數小時或幾週後發生", "可造成結膜紅腫", "有造成角膜內皮細胞傷害的可能", "常因接觸到硫柳汞鈉（thiomerosal sodium）或氯化苯二甲烴銨（benzalkonium chloride）所引起"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02626', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何種情況是配戴隱形眼鏡後，產生的急性紅眼反應，應馬上用生理食鹽水沖洗眼睛，再就醫？', '["使用雙氧水（HO）護理液，忽略中和步驟，直接將鏡片放入眼睛", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02627', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '2', '["眼睛乾", "眼睛感染", "想睡覺", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02628', 'optician', 'optician-moex-106-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡追蹤照護檢查的時機，下列敘述何者錯誤？', '["使用日拋型隱形眼鏡者，應在連續配戴數小時後的下午進行檢查", "對於過夜配戴鏡片者，睡醒後越早檢查越好", "檢查者對隱形眼鏡表現及患者的遵囑性皆無疑慮時，每3-6個月可複檢一次", "無須追蹤照護檢查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "62c9a3599d15", "answer_pdf_sha1": "1ebc5f4e77dc", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
